  "architecture": {
    "components": [
      { "name": "Order Management", "responsibility": "Lifecycle of an order from placement through completion, including state machine transitions", "boundaries": "Owns order aggregate; does not own menu, payment, or delivery state directly" },
      { "name": "Restaurant Management", "responsibility": "Restaurant profiles, menus, availability, hours, capacity", "boundaries": "Owns restaurant and menu aggregates; publishes menu/availability events" },
      { "name": "Customer Management", "responsibility": "Customer profiles, addresses, preferences, order history", "boundaries": "Owns customer aggregate; does not own payment instruments directly" },
      { "name": "Delivery / Dispatch", "responsibility": "Driver matching, route optimization, real-time tracking, delivery state machine", "boundaries": "Owns delivery and driver-assignment aggregates; consumes order events" },
      { "name": "Payment", "responsibility": "Payment processing, refunds, restaurant payouts, driver earnings", "boundaries": "Owns payment/transaction aggregates; integrates with external payment gateway" },
      { "name": "Pricing & Promotions", "responsibility": "Menu pricing, delivery fees, surge pricing, promo codes, discounts", "boundaries": "Stateless calculation service; reads from restaurant and promotion data" },
      { "name": "Notification", "responsibility": "Push notifications, SMS, email for order status, driver updates, promotions", "boundaries": "Generic supporting service; consumes domain events, owns no core state" },
      { "name": "Search & Discovery", "responsibility": "Restaurant search, filtering, ranking, recommendations", "boundaries": "Read-optimized projection; consumes restaurant/menu events" },
      { "name": "Real-Time Tracking", "responsibility": "Live driver location, ETA calculation, WebSocket/SSE delivery to clients", "boundaries": "High-frequency writes; isolated from transactional order flow" }
    ],
    "interfaces": [
      { "from": "Customer Client", "to": "Order Management", "contract": "Place order, cancel order, view order status", "coupling_type": "synchronous request" },
      { "from": "Order Management", "to": "Restaurant Management", "contract": "Validate menu items, confirm restaurant acceptance", "coupling_type": "depends on latency requirements — sync or async" },
      { "from": "Order Management", "to": "Payment", "contract": "Authorize payment on order placement, capture on delivery", "coupling_type": "synchronous (authorization must succeed before order confirmation)" },
      { "from": "Order Management", "to": "Delivery / Dispatch", "contract": "OrderAcceptedByRestaurant event triggers driver matching", "coupling_type": "event-driven async" },
      { "from": "Delivery / Dispatch", "to": "Real-Time Tracking", "contract": "Driver location updates at high frequency", "coupling_type": "fire-and-forget / streaming" },
      { "from": "Order Management", "to": "Notification", "contract": "Order state change events trigger notifications", "coupling_type": "event-driven async" },
      { "from": "Customer Client", "to": "Search & Discovery", "contract": "Search restaurants, filter by cuisine/rating/distance", "coupling_type": "synchronous read" },
      { "from": "Payment", "to": "Restaurant Management", "contract": "Payout settlement events", "coupling_type": "async batch or event" }
    ],
    "data_flow": "Customer searches restaurants (read path) → places order (write path: Order → Payment auth → Restaurant confirmation) → Restaurant accepts (event) → Dispatch assigns driver (event) → Driver picks up → Real-time tracking streams location → Driver delivers → Payment captured → Payouts settled. Each major transition is a domain event that downstream contexts react to.",
    "patterns_used": []
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Ordering",
        "classification": "core",
        "aggregates": ["Order (root: OrderId, contains OrderLineItems, tracks OrderStatus state machine)", "Cart (transient, pre-order)"]
      },
      {
        "name": "Delivery & Dispatch",
        "classification": "core",
        "aggregates": ["Delivery (root: DeliveryId, tracks pickup/dropoff/status)", "DriverAssignment (matching logic)", "DriverAvailability"]
      },
      {
        "name": "Restaurant",
        "classification": "core",
        "aggregates": ["Restaurant (root: RestaurantId, contains Menu, MenuItems, Hours, Capacity)"]
      },
      {
        "name": "Customer",
        "classification": "supporting",
        "aggregates": ["Customer (root: CustomerId, contains SavedAddresses, Preferences)"]
      },
      {
        "name": "Payment & Billing",
        "classification": "generic",
        "aggregates": ["Transaction (root: TransactionId)", "Payout", "Refund"]
      },
      {
        "name": "Pricing & Promotions",
        "classification": "supporting",
        "aggregates": ["PromoCode", "PricingRule", "SurgePricingConfig"]
      },
      {
        "name": "Notification",
        "classification": "generic",
        "aggregates": ["NotificationTemplate", "NotificationLog"]
      },
      {
        "name": "Search & Discovery",
        "classification": "supporting",
        "aggregates": ["RestaurantProjection (read model optimized for search)"]
      }
    ],
    "context_map": [
      { "upstream": "Ordering", "downstream": "Delivery & Dispatch", "relationship": "Customer-Supplier (Ordering publishes OrderAccepted; Dispatch consumes)" },
      { "upstream": "Restaurant", "downstream": "Ordering", "relationship": "Conformist (Ordering conforms to Restaurant's menu model for validation)" },
      { "upstream": "Ordering", "downstream": "Payment & Billing", "relationship": "Customer-Supplier (Ordering requests auth/capture; Payment conforms to order lifecycle)" },
      { "upstream": "Restaurant", "downstream": "Search & Discovery", "relationship": "Published Language (Restaurant publishes menu/availability; Search builds read projections)" },
      { "upstream": "Ordering", "downstream": "Notification", "relationship": "Customer-Supplier (order events trigger notifications)" },
      { "upstream": "Payment & Billing", "downstream": "Restaurant", "relationship": "Customer-Supplier (Payment settles payouts to restaurants)" },
      { "upstream": "Delivery & Dispatch", "downstream": "Notification", "relationship": "Customer-Supplier (delivery status events trigger driver/customer notifications)" }
    ]
  },

  "trade_offs": [
    {
      "decision": "Cannot recommend microservices vs modular monolith",
      "gains": "Avoiding premature distributed-system complexity if scale is small; avoiding monolith bottleneck if scale is large",
      "sacrifices": "Decision deferred — team cannot begin infrastructure provisioning",
      "alternatives_considered": ["Microservices per bounded context", "Modular monolith with extractable modules", "Hybrid: monolith + separated real-time tracking service"]
    },
    {
      "decision": "Cannot recommend specific event infrastructure",
      "gains": "Kafka offers durability and replay; SQS/SNS is simpler operationally; in-process events are simplest",
      "sacrifices": "Decision deferred — affects every inter-context integration",
      "alternatives_considered": ["Apache Kafka", "AWS SNS/SQS", "Redis Streams", "In-process event bus (modular monolith)"]
    },
    {
      "decision": "Cannot recommend database strategy",
      "gains": "Shared DB simplifies transactions; DB-per-service enables independent scaling",
      "sacrifices": "Affects data consistency model, operational complexity, and team autonomy",
      "alternatives_considered": ["Single relational DB with schema-per-context", "Database per service", "Polyglot persistence (relational for orders, Redis for tracking, Elasticsearch for search)"]
    }
