  "flexibility_points": [
    { "area": "Payment gateway integration", "evolution_path": "Abstract behind an ACL so Stripe/Braintree/Adyen can be swapped without touching order logic" },
    { "area": "Notification channels", "evolution_path": "Channel-agnostic event consumption — add new channels (WhatsApp, in-app) without modifying upstream contexts" },
    { "area": "Search infrastructure", "evolution_path": "Read projection can migrate from DB queries to Elasticsearch/Algolia independently" },
    { "area": "Pricing engine", "evolution_path": "Stateless calculation allows rule changes without schema migrations; can evolve to ML-based dynamic pricing" },
    { "area": "Dispatch algorithm", "evolution_path": "Driver matching strategy is encapsulated — can evolve from simple proximity to ML-optimized routing" }
  ],

  "rigidity_points": [
    { "area": "Order state machine", "reason": "Order lifecycle transitions (placed → confirmed → preparing → ready → picked_up → delivered → completed) are a core invariant. Changes here cascade to payment, delivery, and notification." },
    { "area": "Payment authorization flow", "reason": "Auth-before-confirm is a financial correctness invariant. Must remain synchronous and transactionally consistent." },
    { "area": "Restaurant-Order menu validation", "reason": "Orders must validate against current menu/pricing at placement time. This coupling is intentional and must not be relaxed." }
  ],

  "risks": [
    { "risk": "Distributed transaction complexity across Order → Payment → Restaurant acceptance", "severity": "critical", "mitigation": "Saga pattern with compensating actions (e.g., release payment auth if restaurant rejects). Exact implementation depends on architecture decision." },
    { "risk": "Real-time tracking at scale creates extreme write pressure", "severity": "high", "mitigation": "Isolate tracking into its own data store (Redis/TimescaleDB) with separate scaling characteristics. Must know expected driver count." },
    { "risk": "Dispatch/matching under high concurrency causes double-assignment of drivers", "severity": "high", "mitigation": "Optimistic locking or distributed lock on driver assignment. Aggregate design must enforce single-assignment invariant." },
    { "risk": "Menu/pricing staleness — customer sees stale price, pays different amount", "severity": "high", "mitigation": "Version menu items; validate price at order placement against current version; reject or notify on mismatch." },
    { "risk": "Surge pricing without clear business rules creates customer trust issues", "severity": "medium", "mitigation": "Business/product decision needed — transparent pricing display, caps, opt-in. Not purely architectural." },
    { "risk": "Over-engineering for unknown scale", "severity": "medium", "mitigation": "Start with modular monolith IF scale is modest; extract services at proven bottlenecks. But this requires knowing the scale target." }
  ],

  "implementation_guidance": {
    "recommended_approach": "",
