      "routed_to": "Bird",
      "options": [
        "Provide NFRs and constraints so a specific architecture can be recommended",
        "Define an MVP scope (e.g., single city, one payment method, basic dispatch) and I will design for that",
        "Accept a reference architecture document covering multiple scale tiers with decision points"
      ],
      "recommendation": "Define the MVP scope and scale tier first. The domain model above is stable regardless of architecture choice, but every infrastructure and pattern decision depends on knowing the scale, team size, and timeline."
    }
  ],

  "confidence": {
    "level": 45,
    "high_confidence_areas": [
      "Bounded context identification — Ordering, Delivery, Restaurant, Payment, Search are natural seams in any food delivery platform",
      "Context map relationships — upstream/downstream directions are driven by domain semantics, not implementation",
      "Core invariants — order state machine, payment auth flow, menu validation at placement time",
      "Flexibility and rigidity points — these hold regardless of scale or technology choices"
    ],
    "low_confidence_areas": [
      "Deployment topology — microservices vs monolith vs hybrid cannot be decided without scale/team constraints",
      "Event infrastructure — Kafka vs SQS vs in-process depends on throughput, durability, and ops capability",
      "Database strategy — polyglot vs shared depends on team size, consistency requirements, and operational maturity",
      "Real-time tracking architecture — WebSocket fanout, location update frequency, and storage all depend on driver count and latency SLAs"
    ],
    "assumptions": [
      "This is a new platform (greenfield), not a redesign of an existing system",
      "Standard three-sided marketplace model (customers, restaurants, drivers)",
      "Online payment (not cash-on-delivery) is the primary model",
      "Mobile apps for customers and drivers, web dashboard for restaurants"
    ]
  }
}

